224.answer:
Use backtracking.

```js
function permutations(str) {
  const chars = str.split('');
  const result = [];
  const used = Array(chars.length).fill(false);

  function backtrack(path) {
    if (path.length === chars.length) {
      result.push(path.join(''));
      return;
    }

    for (let i = 0; i < chars.length; i++) {
      if (used[i]) continue;

      used[i] = true;
      path.push(chars[i]);
      backtrack(path);
      path.pop();
      used[i] = false;
    }
  }

  backtrack([]);
  return result;
}

console.log(permutations("abc"));
// ["abc", "acb", "bac", "bca", "cab", "cba"]
```

If you want unique permutations for inputs with duplicate characters like `"aab"`, use this version:

```js
function uniquePermutations(str) {
  const chars = str.split('').sort();
  const result = [];
  const used = Array(chars.length).fill(false);

  function backtrack(path) {
    if (path.length === chars.length) {
      result.push(path.join(''));
      return;
    }

    for (let i = 0; i < chars.length; i++) {
      if (used[i]) continue;
      if (i > 0 && chars[i] === chars[i - 1] && !used[i - 1]) continue;

      used[i] = true;
      path.push(chars[i]);
      backtrack(path);
      path.pop();
      used[i] = false;
    }
  }

  backtrack([]);
  return result;
}
```

Time complexity is `O(n * n!)`.

