from collections import deque

class Codec:
    def serialize(self, root):
        if not root:
            return ""

        result = []
        queue = deque([root])

        while queue:
            node = queue.popleft()
            if node is None:
                result.append("null")
                continue

            result.append(str(node.val))
            queue.append(node.left)
            queue.append(node.right)

        while result and result[-1] == "null":
            result.pop()

        return ",".join(result)

