Breadth-first search (BFS) explores a graph **level by level**.

For an unweighted grid:
- Each cell is a node.
- Moves to neighboring cells are edges.
- Because every move costs the same, BFS finds the **shortest path length**.

### How it works
1. Start from the source cell.
2. Put it in a queue.
3. Repeatedly:
   - Pop the front cell.
   - Visit its valid neighbors.
   - If a neighbor hasn’t been seen, mark it visited, record its distance as `current + 1`, and push it into the queue.
4. When you reach the target, its recorded distance is the shortest path length.

### Why BFS gives the shortest path
BFS visits all cells at distance `0`, then all at distance `1`, then `2`, and so on.  
So the first time you reach the target, you reached it using the fewest moves.

---

## Go implementation

This version assumes:
- `grid[r][c] == 0` means open cell
- `grid[r][c] == 1` means blocked cell
- Movement is 4-directional: up, down, left, right

```go
package main

import "fmt"

type Point struct {
	r, c int
}

func shortestPathLength(grid [][]int, start, target Point) int {
	rows := len(grid)
	if rows == 0 {
		return -1
	}
	cols := len(grid[0])

	inBounds := func(r, c int) bool {
		return r >= 0 && r < rows && c >= 0 && c < cols
	}

	if !inBounds(start.r, start.c) || !inBounds(target.r, target.c) {
		return -1
	}
	if grid[start.r][start.c] == 1 || grid[target.r][target.c] == 1 {
		return -1
	}
	if start == target {
		return 0
	}

	visited := make([][]bool, rows)
	dist := make([][]int, rows)
	for i := range visited {
		visited[i] = make([]bool, cols)
		dist[i] = make([]int, cols)
	}

	dirs := [][2]int{
		{-1, 0},
		{1, 0},
		{0, -1},
		{0, 1},
	}

	queue := []Point{start}
	visited[start.r][start.c] = true

	for len(queue) > 0 {
		cur := queue[0]
		queue = queue[1:]

		for _, d := range dirs {
			nr, nc := cur.r+d[0], cur.c+d[1]

			if !inBounds(nr, nc) || visited[nr][nc] || grid[nr][nc] == 1 {
				continue
			}

			visited[nr][nc] = true
			dist[nr][nc] = dist[cur.r][cur.c] + 1

			if nr == target.r && nc == target.c {
				return dist[nr][nc]
			}

			queue = append(queue, Point{nr, nc})
		}
	}

	return -1
}

func main() {
	grid := [][]int{
		{0, 0, 0, 1},
		{1, 1, 0, 1},
		{0, 0, 0, 0},
		{0, 1, 1, 0},
	}

	start := Point{0, 0}
	target := Point{3, 3}

	fmt.Println(shortestPathLength(grid, start, target)) // 6
}
```

## Complexity
- **Time:** `O(rows * cols)`
- **Space:** `O(rows * cols)`

