        System.out.println("Minimum tour cost: " + bestCost);
        System.out.print("Best tour: ");
        for (int i = 0; i < bestPath.length; i++) {
            System.out.print(bestPath[i]);
            if (i < bestPath.length - 1) {
                System.out.print(" -> ");
            }
        }
