Prim’s algorithm builds a minimum spanning tree (MST) greedily:

- Start from any node.
- Repeatedly add the cheapest edge that connects a visited node to an unvisited node.
- Keep going until all nodes are included.

Why it works:
- At each step, it chooses the lightest edge crossing the cut between visited and unvisited vertices.
- By the cut property, that edge is always safe to include in some MST.

Using a priority queue:
- Store candidate edges `(weight, to)` in a min-heap.
- Pop the smallest edge.
- If its destination is already visited, skip it.
- Otherwise, mark it visited, add its weight to the answer, and push its outgoing edges.

Time complexity:
- With an adjacency list and heap: `O((V + E) log V)` or commonly `O(E log V)`.

Here’s a Go implementation that returns the total MST weight for a connected undirected graph:

```go
package main

import (
	"container/heap"
	"fmt"
)

type Edge struct {
	to     int
	weight int
}

type Item struct {
	node   int
	weight int
}

type PriorityQueue []Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].weight < pq[j].weight
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x any) {
	*pq = append(*pq, x.(Item))
}

func (pq *PriorityQueue) Pop() any {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[:n-1]
	return item
}

// primMST returns the total weight of the minimum spanning tree.
// n is the number of vertices labeled [0..n-1].
// graph is an adjacency list for an undirected weighted graph.
func primMST(n int, graph [][]Edge) int {
	if n == 0 {
		return 0
	}

	visited := make([]bool, n)
	pq := &PriorityQueue{}
	heap.Init(pq)

	heap.Push(pq, Item{node: 0, weight: 0})
	totalWeight := 0
	visitedCount := 0

	for pq.Len() > 0 && visitedCount < n {
		curr := heap.Pop(pq).(Item)

		if visited[curr.node] {
			continue
		}

		visited[curr.node] = true
		visitedCount++
		totalWeight += curr.weight

		for _, edge := range graph[curr.node] {
			if !visited[edge.to] {
				heap.Push(pq, Item{
					node:   edge.to,
					weight: edge.weight,
				})
			}
		}
	}

	// If visitedCount < n, the graph was disconnected.
	// In that case, no spanning tree exists for the full graph.
	if visitedCount < n {
		panic("graph is disconnected")
	}

	return totalWeight
}

func addUndirectedEdge(graph [][]Edge, u, v, w int) {
	graph[u] = append(graph[u], Edge{to: v, weight: w})
	graph[v] = append(graph[v], Edge{to: u, weight: w})
}

func main() {
	n := 5
	graph := make([][]Edge, n)

	addUndirectedEdge(graph, 0, 1, 2)
	addUndirectedEdge(graph, 0, 3, 6)
	addUndirectedEdge(graph, 1, 2, 3)
	addUndirectedEdge(graph, 1, 3, 8)
	addUndirectedEdge(graph, 1, 4, 5)
	addUndirectedEdge(graph, 2, 4, 7)
	addUndirectedEdge(graph, 3, 4, 9)

	fmt.Println(primMST(n, graph)) // 16
}
```

