A heap is a **complete binary tree** that satisfies a **heap property**:

- **Min-heap**: every node is `<=` its children, so the smallest element is at the root.
- **Max-heap**: every node is `>=` its children, so the largest element is at the root.

In practice, heaps are usually stored in an **array**, not with tree nodes.

For index `i`:
- `left child = 2*i + 1`
- `right child = 2*i + 2`
- `parent = (i - 1) / 2`

### Core operations
For a **min-heap**:
- **insert(x)**: add at the end, then **bubble up**
- **getMin()**: return the root
- **extractMin()**: remove root, move last element to root, then **bubble down**

Time complexity:
- `insert`: `O(log n)`
- `extractMin`: `O(log n)`
- `getMin`: `O(1)`

---

## C++ Min-Heap implementation

I assume you meant the standard operations: **insert**, **getMin**, and **extractMin**.

```cpp
#include <iostream>
#include <vector>
#include <stdexcept>
using namespace std;

class MinHeap {
private:
    vector<int> heap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;

            if (heap[parent] <= heap[index]) {
                break;
            }

            swap(heap[parent], heap[index]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int size = heap.size();

        while (true) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int smallest = index;

            if (left < size && heap[left] < heap[smallest]) {
                smallest = left;
            }

            if (right < size && heap[right] < heap[smallest]) {
                smallest = right;
            }

            if (smallest == index) {
                break;
            }

            swap(heap[index], heap[smallest]);
            index = smallest;
        }
    }

public:
    void insert(int value) {
        heap.push_back(value);
        heapifyUp(heap.size() - 1);
    }

    int getMin() const {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }
        return heap[0];
    }

    int extractMin() {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }

        int minValue = heap[0];
        heap[0] = heap.back();
        heap.pop_back();

        if (!heap.empty()) {
            heapifyDown(0);
        }

        return minValue;
    }

    bool empty() const {
        return heap.empty();
    }

    void print() const {
        for (int x : heap) {
            cout << x << " ";
        }
        cout << endl;
    }
};

int main() {
    MinHeap h;

    h.insert(10);
    h.insert(4);
    h.insert(15);
    h.insert(2);
    h.insert(8);

    cout << "Heap elements: ";
    h.print();

    cout << "Min: " << h.getMin() << endl;
    cout << "Extracted min: " << h.extractMin() << endl;
    cout << "New min: " << h.getMin() << endl;

    return 0;
}
```

---

## Example flow

Insert: `10, 4, 15, 2, 8`

Heap array evolves roughly as:
- `[10]`
- `[4, 10]`
- `[4, 10, 15]`
- `[2, 4, 15, 10]`
- `[2, 4, 15, 10, 8]`

So:
- `getMin()` returns `2`
- `extractMin()` removes `2`
- heap reorganizes so the next minimum is at the root

