The **Template Method** pattern defines the **skeleton of an algorithm** in a base class, while letting subclasses override specific steps without changing the overall flow.

### When to use it
Use it when:
- multiple classes follow the same high-level process
- some steps are shared
- some steps vary by implementation

### Structure
Typically:
- a **base class** contains the template method
- the template method calls a sequence of smaller methods
- subclasses override the variable steps

### Example flow for a parser
A parser might always:
1. load raw input
2. validate it
3. parse it
4. transform it
5. return the result

CSV and JSON parsers share that workflow, but differ in the parsing step.

---

## C# implementation

```csharp
using System;
using System.Collections.Generic;
using System.Text.Json;

public abstract class DataParser
{
    // Template method
    public List<Dictionary<string, string>> ParseData(string input)
    {
        string cleaned = Load(input);
        Validate(cleaned);
        var parsed = Parse(cleaned);
        return Transform(parsed);
    }

    protected virtual string Load(string input)
    {
        Console.WriteLine("Loading data...");
        return input.Trim();
    }

    protected virtual void Validate(string input)
    {
        if (string.IsNullOrWhiteSpace(input))
            throw new ArgumentException("Input cannot be empty.");
    }

    protected abstract object Parse(string input);

    protected abstract List<Dictionary<string, string>> Transform(object parsedData);
}

public class CsvParser : DataParser
{
    protected override object Parse(string input)
    {
        Console.WriteLine("Parsing CSV data...");
        var lines = input.Split('\n', StringSplitOptions.RemoveEmptyEntries);
        var rows = new List<string[]>();

        foreach (var line in lines)
        {
            rows.Add(line.Trim().Split(','));
        }

        return rows;
    }

    protected override List<Dictionary<string, string>> Transform(object parsedData)
    {
        Console.WriteLine("Transforming CSV data...");
        var rows = (List<string[]>)parsedData;
        var result = new List<Dictionary<string, string>>();

        if (rows.Count < 2)
            return result;

        var headers = rows[0];

        for (int i = 1; i < rows.Count; i++)
        {
            var item = new Dictionary<string, string>();
            for (int j = 0; j < headers.Length && j < rows[i].Length; j++)
            {
                item[headers[j]] = rows[i][j];
            }
            result.Add(item);
        }

        return result;
    }
}

public class JsonParser : DataParser
{
    protected override object Parse(string input)
    {
        Console.WriteLine("Parsing JSON data...");
        return JsonDocument.Parse(input);
    }

    protected override List<Dictionary<string, string>> Transform(object parsedData)
    {
        Console.WriteLine("Transforming JSON data...");
        var doc = (JsonDocument)parsedData;
        var result = new List<Dictionary<string, string>>();

        if (doc.RootElement.ValueKind != JsonValueKind.Array)
            throw new FormatException("Expected a JSON array.");

        foreach (var element in doc.RootElement.EnumerateArray())
        {
            var item = new Dictionary<string, string>();

            foreach (var property in element.EnumerateObject())
            {
                item[property.Name] = property.Value.ToString();
            }

            result.Add(item);
        }

        return result;
    }
}

public class Program
{
    public static void Main()
    {
        string csvInput = @"
name,age,city
Alice,30,Paris
Bob,25,London";

        string jsonInput = @"
[
  { ""name"": ""Alice"", ""age"": 30, ""city"": ""Paris"" },
  { ""name"": ""Bob"", ""age"": 25, ""city"": ""London"" }
]";

        DataParser csvParser = new CsvParser();
        DataParser jsonParser = new JsonParser();

        var csvResult = csvParser.ParseData(csvInput);
        var jsonResult = jsonParser.ParseData(jsonInput);

        Console.WriteLine("\nCSV Result:");
        PrintResult(csvResult);

        Console.WriteLine("\nJSON Result:");
        PrintResult(jsonResult);
    }

    private static void PrintResult(List<Dictionary<string, string>> data)
    {
        foreach (var row in data)
        {
            foreach (var pair in row)
            {
                Console.Write($"{pair.Key}: {pair.Value}  ");
            }
            Console.WriteLine();
        }
    }
}
```

---

## Why this is Template Method
`ParseData()` is the template method:
- `Load()`
- `Validate()`
- `Parse()`
- `Transform()`

The overall algorithm stays fixed in `DataParser`, while `CsvParser` and `JsonParser` customize the parsing behavior.

## Benefits
