```js
function deepClone(value, seen = new Map()) {
  if (value === null || typeof value !== 'object') return value;

  if (seen.has(value)) return seen.get(value);

  if (value instanceof Date) {
    const copy = new Date(value.getTime());
    seen.set(value, copy);
    return copy;
  }

  if (value instanceof RegExp) {
    const copy = new RegExp(value.source, value.flags);
    copy.lastIndex = value.lastIndex;
    seen.set(value, copy);
    return copy;
  }

  if (value instanceof Map) {
    const copy = new Map();
    seen.set(value, copy);
    for (const [k, v] of value) {
      copy.set(deepClone(k, seen), deepClone(v, seen));
    }
    return copy;
  }

  if (value instanceof Set) {
    const copy = new Set();
    seen.set(value, copy);
    for (const item of value) {
      copy.add(deepClone(item, seen));
    }
    return copy;
  }

  if (Array.isArray(value)) {
    const copy = [];
    seen.set(value, copy);
    for (const item of value) {
      copy.push(deepClone(item, seen));
    }
    return copy;
  }

  const copy = Object.create(Object.getPrototypeOf(value));
  seen.set(value, copy);

  for (const key of Reflect.ownKeys(value)) {
    const desc = Object.getOwnPropertyDescriptor(value, key);
    if (!desc) continue;

    if ('value' in desc) {
      desc.value = deepClone(desc.value, seen);
    }

    Object.defineProperty(copy, key, desc);
  }

  return copy;
}
```

Preserves circular references and shared identity, e.g.:

```js
const shared = { x: 1 };
const obj = {
  a: shared,
  b: shared,
  arr: [shared],
  date: new Date(),
  map: new Map([[shared, /abc/g]]),
};
obj.self = obj;

const cloned = deepClone(obj);

console.log(cloned !== obj); // true
console.log(cloned.a === cloned.b); // true
console.log(cloned.a === cloned.arr[0]); // true
console.log(cloned.self === cloned); // true
console.log(cloned.map.keys().next().value === cloned.a); // true
```

