func readTextFileOrDefault(path string, defaultValue string) (string, error) {
	info, err := os.Stat(path)
	if err != nil {
		if errors.Is(err, fs.ErrNotExist) {
			return defaultValue, nil
		}
		return "", err
	}
	if info.IsDir() {
		return "", errors.New("path refers to a directory")
