The bottleneck is **issuing a system call per byte** (`read(fd, &c, 1)` in a loop). On multi-GB files, the asymptotic work is still linear in file size, but the constant factor is catastrophic because you pay kernel/userspace transition overhead **N times** for **N bytes**.

## Big-O
Let `N` = file size in bytes, `B` = buffer size.

### Before
- **Time:** `O(N)`
- **System calls:** `O(N)`
- **Space:** `O(1)`

### After using buffered reads
Read chunks like 64 KiB–1 MiB and process bytes from memory.

- **Time:** `O(N)`
- **System calls:** `O(N / B)`
- **Space:** `O(B)`

So the Big-O time stays `O(N)`, but throughput improves dramatically because syscall count drops by a factor of `B`.

## Bad pattern
```c
char c;
while (read(fd, &c, 1) == 1) {
    process_byte(c);
}
```

## Better approach
```c
#include <unistd.h>
#include <fcntl.h>
#include <stdlib.h>
#include <stdio.h>
#include <errno.h>

#define BUF_SIZE (1024 * 1024)  // 1 MiB

void process_byte(unsigned char c);

int main(int argc, char **argv) {
    if (argc != 2) {
        fprintf(stderr, "usage: %s <file>\n", argv[0]);
        return 1;
    }

    int fd = open(argv[1], O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    unsigned char *buf = malloc(BUF_SIZE);
    if (!buf) {
        perror("malloc");
        close(fd);
        return 1;
    }

    for (;;) {
        ssize_t n = read(fd, buf, BUF_SIZE);
        if (n < 0) {
            perror("read");
            free(buf);
            close(fd);
            return 1;
        }
        if (n == 0) {
            break;
        }

        for (ssize_t i = 0; i < n; i++) {
            process_byte(buf[i]);
        }
    }

    free(buf);
    close(fd);
    return 0;
}
```

## Why this is faster
- Fewer syscalls
- Better use of kernel readahead
- Better cache behavior from sequential memory access
- Much lower syscall overhead on large files

## Even simpler option
If you’re using `stdio`, `fread()` already does buffering:

```c
#include <stdio.h>
#include <stdlib.h>

#define BUF_SIZE (1024 * 1024)

void process_byte(unsigned char c);

int main(int argc, char **argv) {
    if (argc != 2) return 1;

    FILE *fp = fopen(argv[1], "rb");
    if (!fp) {
        perror("fopen");
        return 1;
    }

    unsigned char *buf = malloc(BUF_SIZE);
    if (!buf) {
        perror("malloc");
        fclose(fp);
        return 1;
    }

    size_t n;
    while ((n = fread(buf, 1, BUF_SIZE, fp)) > 0) {
        for (size_t i = 0; i < n; i++) {
            process_byte(buf[i]);
        }
    }

    if (ferror(fp)) {
        perror("fread");
    }

    free(buf);
    fclose(fp);
    return 0;
}
```

## Summary
- **Bottleneck:** one-byte-at-a-time `read()` calls
- **Fix:** buffered/block reads
- **Before:** `O(N)` time, `O(N)` syscalls, `O(1)` space
- **After:** `O(N)` time, `O(N/B)` syscalls, `O(B)` space

If you want, I can also show an `mmap()` version and explain when it beats or loses to `read()`.

